steps.script:
for t in ToastManager.active_toasts:
	if is_instance_valid(t):
		t.queue_free()
ToastManager.active_toasts.clear()
InputDeviceManager.input_mode = InputDeviceManager.InputMode.KBM
var mc = tree.current_scene.movement_controller
mc._post_disembark_ui_update("Z_BOYZ")
var found = false
for toast in ToastManager.active_toasts:
	if not is_instance_valid(toast):
		continue
	for c in toast.get_children():
		if c is Label and "disembarked" in c.text and "Move" in c.text and "movement panel" in c.text:
			found = true
return found

